text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표",
        "decision": "Smoke 테스트가 통과하면 공개 릴리스 목표는 금요일 15:00 KST로 정한다.",
        "certainty": "confirmed"
      },
      {
        "topic": "packageName 불일치 대응",
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다.",
        "certainty": "confirmed"
      }
    ],
    "rejected_proposals": [
      {
        "topic": "즉시 스크립트 수정",
        "proposal": "smoke-theme-pack.mjs에서 packageName 불일치를 무시하도록 변경한다.",
        "decision": "거부됨",
        "certainty": "confirmed"
      }
    ],
    "internal_stretch_goals": [
      {
        "topic": "중간 목표 일정",
        "goal": "수요일 공개 릴리스를 내부 스트레치 목표로 검토했다.",
        "status": "내부 목표에만 해당하며 최종 결정은 아님",
        "certainty": "confirmed"
      },
      {
        "topic": "README 검토",
        "goal": "README 설치 절차를 가능하면 목요일까지 검토한다.",
        "status": "목표로 언급되었으나 오너는 지정되지 않음",
        "certainty": "confirmed"
      }
    ],
    "non_decisions": [
      {
        "topic": "공개 릴리스 승인",
        "detail": "최종 공개 릴리스 승인 조건은 smoke 통과로 연결되었지만, 승인 주체는 확정되지 않았다.",
        "certainty": "confirmed"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로",
        "impact": "릴리스를 지연시킬 수 있다.",
        "certainty": "confirmed"
      },
      {
        "risk": "README 설치 절차가 오래됨",
        "impact": "릴리스 노트가 사용자에게 잘못된 안내를 줄 수 있다.",
        "certainty": "confirmed"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한은 누구에게 있는가?",
        "certainty": "confirmed"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?",
        "certainty": "confirmed"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 smoke 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "Friday 10:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 `action_items.md`에 실패 triage 노트를 작성한다.",
      "due": "Friday 12:00 KST",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 smoke 결과를 올린 뒤 생성된 tarball 경로를 확인한다.",
      "due": "unspecified",
      "status": "confirmed",
      "source_certainty": "confirmed"
    },
    {
      "owner": "Unassigned",
      "task": "README 설치 절차를 검토한다.",
      "due": "Thursday if possible",
      "status": "proposed but unassigned",
      "source_certainty": "confirmed"
    }
  ],
  "followup_note": {
    "next_checks": [
      "Minjun의 smoke 테스트 재실행 결과를 확인한다.",
      "Doyun의 실패 triage 노트를 확인한다.",
      "tarball 경로가 올바른지 Hara의 점검 결과를 확인한다.",
      "README 설치 절차 검토의 담당자를 확정한다.",
      "최종 릴리스 승인 권한을 확인한다.",
      "릴리스 노트에 내부 수요일 스트레치 목표를 넣을지 결정한다."
    ],
    "do_not_invent": [
      "고객명",
      "외부 파트너명",
      "예산",
      "보안 사고",
      "운영 장애",
      "법적 승인 요건",
      "지정되지 않은 오너",
      "명시되지 않은 데드라인"
    ],
    "source_boundary": "이 요약은 제공된 공용 안전 합성 메모만을 근거로 하며, 외부 사실이나 누락된 세부사항을 보완하지 않는다."
  },
  "non_invention_rules": [
    "고객 또는 외부 파트너를 추정하지 않는다.",
    "예산, 보안, 장애, 법무, 승인권자, 데드라인을 새로 만들지 않는다.",
    "명시된 내용과 충돌하는 해석을 추가하지 않는다.",
    "확정된 결정, 거절된 제안, 내부 스트레치 목표, 위험, 열린 질문을 섞지 않고 구분한다.",
    "오너가 없는 항목은 오너를 임의로 지정하지 않는다.",
    "기록에 없는 완료 상태나 성공 여부를 단정하지 않는다."
  ]
}
